310â†’// Build backend-specific permission arguments
311â†’// Maps our internal permission modes to each backend's CLI flags
312â†’function buildPermissionArgs(
313â†’  backend: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' = 'claude',
314â†’  permissionMode?: string,
315â†’  autoAcceptTools?: string[]
