318â†’
319â†’  switch (backend) {
320â†’    case 'claude':
321â†’      // Claude Code: --permission-mode and --allowedTools
322â†’      if (permissionMode && permissionMode !== 'default') {
323â†’        args.push('--permission-mode', permissionMode)
324â†’      }
325â†’      if (autoAcceptTools && autoAcceptTools.length > 0) {
326â†’        for (const tool of autoAcceptTools) {
327â†’          args.push('--allowedTools', tool)
328â†’        }
329â†’      }
330â†’      break
331â†’
332â†’    case 'gemini':
333â†’      // Gemini CLI: --approval-mode (default/auto_edit/yolo) and --allowed-tools
334â†’      // See: https://geminicli.com/docs/get-started/configuration/
335â†’      if (permissionMode) {
336â†’        switch (permissionMode) {
337â†’          case 'acceptEdits':
338â†’            args.push('--approval-mode', 'auto_edit')
339â†’            break
340â†’          case 'dontAsk':
341â†’          case 'bypassPermissions':
342â†’            args.push('--approval-mode', 'yolo')
343â†’            break
344â†’          // 'default' mode = no flag needed
345â†’        }
346â†’      }
347â†’      if (autoAcceptTools && autoAcceptTools.length > 0) {
348â†’        // Gemini uses comma-separated list for --allowed-tools
349â†’        args.push('--allowed-tools', autoAcceptTools.join(','))
350â†’      }
351â†’      break
352â†’
353â†’    case 'codex':
354â†’      // Codex CLI: --full-auto or --dangerously-bypass-approvals-and-sandbox
355â†’      // See: https://developers.openai.com/codex/cli/reference/
356â†’      if (permissionMode) {
