361â†’            break
362â†’          case 'bypassPermissions':
363â†’            args.push('--dangerously-bypass-approvals-and-sandbox')
364â†’            break
365â†’          // 'default' mode = no flag needed
366â†’        }
367â†’      }
368â†’      // Codex doesn't support per-tool auto-accept via CLI flags
369â†’      break
370â†’
371â†’    case 'opencode':
