/**
 * WebSocket Manager - WebSocket handling
 */

import { WebSocket, WebSocketServer } from 'ws'
import { Server } from 'http'
import { log } from './utils'
import { PendingFile } from './types'

export interface WebSocketManagerDeps {
  getToken: () => string
  getPtyManager: () => any
  getPort: () => number
  getTerminalSubscriptions: () => Map<string, Set<WebSocket>>
  getPtyStreams: () => Map<string, Set<WebSocket>>
  getPtyDataBuffer: () => Map<string, string[]>
  getConnectedClients: () => Set<WebSocket>
  getPendingFiles: () => Map<string, PendingFile>
}

export function setupWebSocket(server: Server, deps: WebSocketManagerDeps): WebSocketServer {
  const wss = new WebSocketServer({ noServer: true })

  // Handle upgrade requests manually to support multiple paths
  server.on('upgrade', (req, socket, head) => {
    const url = new URL(req.url || '', `http://localhost:${deps.getPort()}`)
    const pathname = url.pathname

    // Get token from Sec-WebSocket-Protocol header (preferred) or query string (fallback)
    const protocolHeader = req.headers['sec-websocket-protocol'] as string | undefined
    const protocols = protocolHeader?.split(',').map(p => p.trim()) || []
    const tokenFromProtocol = protocols.find(p => p.startsWith('token-'))?.slice(6)
    const tokenFromQuery = url.searchParams.get('token')
    const token = tokenFromProtocol || tokenFromQuery

    log('WebSocket upgrade request', {
      url: req.url,
      pathname,
      hasProtocolToken: !!tokenFromProtocol,
      hasQueryToken: !!tokenFromQuery,
      headers: {
        host: req.headers.host,
        origin: req.headers.origin,
        upgrade: req.headers.upgrade
      }
    })

    // Validate token for all WebSocket connections
    if (token !== deps.getToken()) {
      log('WebSocket auth failed', { providedToken: token?.slice(0, 8) })
      socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n')
      socket.destroy()
      return
    }

    // Handle PTY stream WebSocket: /api/pty/:id/stream
    const ptyStreamMatch = pathname.match(/^\/api\/pty\/([^/]+)\/stream$/)
    if (ptyStreamMatch) {
      const ptyId = ptyStreamMatch[1]
      handlePtyStreamUpgrade(req, socket, head, ptyId, deps)
      return
    }

    // Handle main WebSocket path: /ws
    if (pathname === '/ws') {
      wss.handleUpgrade(req, socket, head, (ws) => {
        wss.emit('connection', ws, req)
      })
      return
    }

    // Unknown WebSocket path
    log('Unknown WebSocket path', { pathname })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
  })

  wss.on('connection', (ws: WebSocket, _req) => {
    log('WebSocket client connected (main)')

    deps.getConnectedClients().add(ws)

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())
        handleWebSocketMessage(ws, msg, deps)
      } catch (e) {
        log('Invalid WebSocket message', { error: String(e) })
      }
    })

    ws.on('close', () => {
      deps.getConnectedClients().delete(ws)

      deps.getTerminalSubscriptions().forEach((subscribers, ptyId) => {
        subscribers.delete(ws)
        if (subscribers.size === 0) {
          deps.getTerminalSubscriptions().delete(ptyId)
        }
      })
      log('WebSocket client disconnected (main)')
    })

    // Send welcome message
    ws.send(JSON.stringify({ type: 'connected', timestamp: Date.now() }))

    // Send any pending files to new client
    sendPendingFilesToClient(ws, deps.getPendingFiles())
  })

  return wss
}

function handlePtyStreamUpgrade(
  req: any,
  socket: any,
  head: any,
  ptyId: string,
  deps: WebSocketManagerDeps
): void {
  const ptyManager = deps.getPtyManager()
  if (!ptyManager || !ptyManager.getProcess(ptyId)) {
    log('PTY stream upgrade failed - PTY not found', { ptyId })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
    return
  }

  const streamWss = new WebSocketServer({ noServer: true })

  streamWss.handleUpgrade(req, socket, head, (ws) => {
    log('PTY stream connected', { ptyId })

    const ptyStreams = deps.getPtyStreams()
    if (!ptyStreams.has(ptyId)) {
      ptyStreams.set(ptyId, new Set())
    }
    ptyStreams.get(ptyId)!.add(ws)

    ws.send(JSON.stringify({ type: 'connected', ptyId }))

    // Flush any buffered data
    flushPtyBuffer(ptyId, ws, deps.getPtyDataBuffer())

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())

        switch (msg.type) {
          case 'input':
            if (msg.data && ptyManager) {
              ptyManager.write(ptyId, msg.data)
            }
            break

          case 'resize':
            if (msg.cols && msg.rows && ptyManager) {
              ptyManager.resize(ptyId, msg.cols, msg.rows)
            }
            break

          case 'ping':
            ws.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
            break

          default:
            log('Unknown PTY stream message type', { type: msg.type, ptyId })
        }
      } catch (e) {
        log('Invalid PTY stream message', { error: String(e), ptyId })
      }
    })

    ws.on('close', () => {
      log('PTY stream disconnected', { ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
      if (ptyStreams.get(ptyId)?.size === 0) {
        ptyStreams.delete(ptyId)
      }
    })

    ws.on('error', (err) => {
      log('PTY stream error', { error: String(err), ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
    })
  })
}

function handleWebSocketMessage(ws: WebSocket, msg: any, deps: WebSocketManagerDeps): void {
  const ptyManager = deps.getPtyManager()
  const terminalSubscriptions = deps.getTerminalSubscriptions()

  switch (msg.type) {
    case 'subscribe':
      if (msg.ptyId) {
        if (!terminalSubscriptions.has(msg.ptyId)) {
          terminalSubscriptions.set(msg.ptyId, new Set())
        }
        terminalSubscriptions.get(msg.ptyId)!.add(ws)
        ws.send(JSON.stringify({ type: 'subscribed', ptyId: msg.ptyId }))

/**
 * Mobile Server - Exposes IPC handlers as HTTP/WebSocket endpoints
 * for mobile app to connect to the desktop host
 */

import express, { Express, Request, Response } from 'express'
import { WebSocketServer, WebSocket } from 'ws'
import { createServer as createHttpServer, Server as HttpServer } from 'http'
import { createServer as createHttpsServer, Server as HttpsServer } from 'https'
import {
  getClientIp,
  getOrCreateFingerprint,
  getFormattedFingerprint,
  getCertificateFingerprint,
  getFormattedCertFingerprint,
  getTlsOptions,
  createNonce,
  verifyNonce,
  startNonceCleanup,
  stopNonceCleanup,
  recordFailedAuth,
  clearRateLimit,
  cleanupEndpointRateLimits
} from '../mobile-security'

import { MobileServerConfig, LocalPty, PendingFile, DEFAULT_PORT } from './types'
import { loadOrCreateToken, regenerateToken as regenerateTokenFn, saveToken } from './token-manager'
import { log, getRendererPath, getLocalIPs, getTailscaleHostname } from './utils'
import {
  setupCorsMiddleware,
  setupStaticMiddleware,
  setupJsonMiddleware,
  setupRateLimitMiddleware,
  setupAuthMiddleware,
  setupIpAccessMiddleware,
  setupEndpointRateLimitMiddleware
} from './middleware'
import {
  setupTerminalRoutes,
  setupWorkspaceRoutes,
  setupBeadsRoutes,
  setupFilesRoutes,
  setupPtyRoutes,
  setupTtsRoutes
} from './routes/index'
import {
  setupWebSocket,
  broadcastTerminalData as wsBroadcastTerminalData,
  broadcastPtyData as wsBroadcastPtyData,
  broadcastPtyExit as wsBroadcastPtyExit
} from './websocket-manager'
import {
  sendFileToMobile as filePushSendFile,
  getPendingFilesList,
  removePendingFile as filePushRemovePendingFile,
  cleanupExpiredFiles
} from './file-push'

export class MobileServer {
  private app: Express
  private server: HttpServer | HttpsServer | null = null
  private wss: WebSocketServer | null = null
  private token: string
  private port: number
  private terminalSubscriptions: Map<string, Set<WebSocket>> = new Map()
  private ptyStreams: Map<string, Set<WebSocket>> = new Map()
  private ptyDataBuffer: Map<string, string[]> = new Map()

  private ptyManager: any = null
  private sessionStore: any = null
  private voiceManager: any = null

  private localPtys: Map<string, LocalPty> = new Map()
  private pendingFiles: Map<string, PendingFile> = new Map()
  private connectedClients: Set<WebSocket> = new Set()

  private rendererPath: string
  private rateLimitCleanupInterval: ReturnType<typeof setInterval> | null = null
  private useTls: boolean = false // TODO: Enable once mobile app has cert pinning
  private certFingerprint: string = ''

  constructor(config: MobileServerConfig = {}) {
    this.port = config.port || DEFAULT_PORT
    this.token = loadOrCreateToken()
    this.rendererPath = getRendererPath()
    this.app = express()
    this.setupMiddleware()
    this.setupRoutes()
  }

  private setupMiddleware(): void {
    setupCorsMiddleware(this.app)
    setupStaticMiddleware(this.app, this.rendererPath)
    setupJsonMiddleware(this.app)
    setupRateLimitMiddleware(this.app)
    setupAuthMiddleware(this.app, () => this.token)
    setupIpAccessMiddleware(this.app)
    setupEndpointRateLimitMiddleware(this.app)
  }

  private setupRoutes(): void {
    // Health check (unauthenticated)
    this.app.get('/health', (req: Request, res: Response) => {
      log('Health check', { clientIp: getClientIp(req) })
      res.json({ status: 'ok', version: '2.0.0' })
    })

    // WebSocket test
    this.app.get('/ws-test', (req: Request, res: Response) => {
      const token = req.query.token as string
      log('WS test request', { providedToken: token?.slice(0, 8), expectedToken: this.token.slice(0, 8), clientIp: getClientIp(req) })
      if (token === this.token) {
        res.json({ ok: true, message: 'Token valid, WebSocket should work' })
      } else {
        res.status(403).json({ ok: false, message: 'Invalid token' })
      }
    })

    // Connection info for QR code (unauthenticated)
    this.app.get('/connect', (_req: Request, res: Response) => {
      const ips = getLocalIPs()
      res.json({
        port: this.port,
        ips,
        fingerprint: getFormattedFingerprint(),
        certFingerprint: this.certFingerprint,
        secure: this.useTls
      })
    })

    // Verify handshake nonce (unauthenticated)
    this.app.post('/verify-handshake', (req: Request, res: Response) => {
      const { nonce } = req.body
      log('Verify handshake request', { nonce: nonce?.slice(0, 8), clientIp: getClientIp(req) })

      if (!nonce || typeof nonce !== 'string') {
        return res.status(400).json({ error: 'Missing nonce' })
      }

      const valid = verifyNonce(nonce)

      if (!valid) {
        const clientIp = getClientIp(req)
        recordFailedAuth(clientIp)
        return res.status(403).json({
          valid: false,
          error: 'Invalid or expired nonce'
        })
      }

