387â†’function buildResumeArgs(
388â†’  backend: string = 'claude',
389â†’  sessionId?: string
390â†’): string[] {
391â†’  if (!sessionId) {
392â†’    return []
393â†’  }
394â†’  switch (backend) {
395â†’    case 'gemini':
396â†’      return ['--resume', sessionId]
397â†’    case 'codex':
398â†’      return ['--resume', sessionId]
399â†’    case 'opencode':
400â†’      return ['--session', sessionId]
401â†’    case 'aider':
402â†’      return ['--restore', sessionId]
403â†’    case 'claude':
404â†’    default:
405â†’      return ['-r', sessionId]
406â†’  }
407â†’}
