409â†’export class PtyManager {
410â†’  private processes: Map<string, ClaudeProcess> = new Map()
411â†’  private dataCallbacks: Map<string, (data: string) => void> = new Map()
412â†’  private exitCallbacks: Map<string, (code: number) => void> = new Map()
413â†’
414â†’  spawn(
415â†’    cwd: string,
416â†’    sessionId?: string,
417â†’    autoAcceptTools?: string[],
418â†’    permissionMode?: string,
419â†’    model?: string,
420â†’    backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
421â†’  ): string {
422â†’    const id = crypto.randomUUID()
423â†’
424â†’    const args: string[] = []
425â†’    args.push(...buildResumeArgs(backend || 'claude', sessionId))
426â†’
427â†’    // Add model if specified (and not default)
428â†’    if (model && model !== 'default') {
429â†’      args.push('--model', model)
430â†’    }
431â†’
432â†’    // Add backend-specific permission arguments
433â†’    const permissionArgs = buildPermissionArgs(
434â†’      backend || 'claude',
435â†’      permissionMode,
436â†’      autoAcceptTools
437â†’    )
438â†’    args.push(...permissionArgs)
439â†’
440â†’    const exe = findExecutable(backend)
441â†’    console.log('Spawning', backend, ':', exe, 'in', cwd, 'with args:', args)
442â†’
443â†’    const ptyOptions: ExtendedPtyForkOptions = {
444â†’      name: 'xterm-256color',
445â†’      cols: 120,
446â†’      rows: 30,
447â†’      cwd,
448â†’      env: getEnhancedEnv(),
449â†’      handleFlowControl: true, // Enable XON/XOFF flow control for better backpressure handling
450â†’    }
451â†’
452â†’    // Windows: use ConPTY for better escape sequence and UTF-8 handling
453â†’    if (isWindows) {
454â†’      ptyOptions.useConpty = true
455â†’    }
456â†’
457â†’    const shell = pty.spawn(exe, args, ptyOptions)
458â†’
459â†’    const proc: ClaudeProcess = {
460â†’      id,
461â†’      pty: shell,
462â†’      cwd,
463â†’      sessionId,
464â†’      backend: backend as
465â†’        | 'claude'
466â†’        | 'gemini'
467â†’        | 'codex'
468â†’        | 'opencode'
469â†’        | 'aider'
470â†’        | undefined,
471â†’      disposables: [],
472â†’      spawnedAt: Date.now(),
473â†’      outputBuffer: new OutputBuffer(),
474â†’    }
475â†’
476â†’    this.processes.set(id, proc)
477â†’
478â†’    // Store disposables from onData/onExit for proper cleanup
479â†’    const dataDisposable = shell.onData(data => {
480â†’      proc.outputBuffer.append(data)
481â†’      const callback = this.dataCallbacks.get(id)
482â†’      if (callback) {
483â†’        callback(data)
484â†’      }
485â†’    })
486â†’    proc.disposables.push(dataDisposable)
487â†’
488â†’    const exitDisposable = shell.onExit(({ exitCode }) => {
489â†’      const callback = this.exitCallbacks.get(id)
490â†’      if (callback) {
491â†’        callback(exitCode)
492â†’      }
493â†’      this.cleanupProcess(id)
494â†’    })
495â†’    proc.disposables.push(exitDisposable)
496â†’
497â†’    return id
498â†’  }
499â†’
500â†’  write(id: string, data: string): void {
501â†’    const proc = this.processes.get(id)
502â†’    if (proc) {
503â†’      proc.pty.write(data)
504â†’    }
505â†’  }
506â†’
507â†’  resize(id: string, cols: number, rows: number): void {
508â†’    const proc = this.processes.get(id)
509â†’    if (!proc) return
510â†’
511â†’    // Skip if dimensions haven't changed
512â†’    if (proc.lastResizeCols === cols && proc.lastResizeRows === rows) return
513â†’
514â†’    // Debounce resize events - Ink-based CLIs (e.g. Gemini) crash with
515â†’    // infinite re-render loops when they receive rapid SIGWINCH during startup
516â†’    if (proc.resizeTimeout) {
517â†’      clearTimeout(proc.resizeTimeout)
518â†’    }
519â†’
520â†’    const elapsed = Date.now() - proc.spawnedAt
521â†’    const isInkBackend = INK_BACKENDS.has(proc.backend || '')
522â†’    // During first 5s of Ink-backend startup, coalesce resizes with 1.5s debounce
523â†’    // to let the CLI finish initialization before sending SIGWINCH
524â†’    const debounceMs = isInkBackend && elapsed < 5000 ? 1500 : 50
525â†’
526â†’    proc.resizeTimeout = setTimeout(() => {
527â†’      proc.resizeTimeout = undefined
528â†’      proc.lastResizeCols = cols
529â†’      proc.lastResizeRows = rows
530â†’      try {
531â†’        proc.pty.resize(cols, rows)
532â†’      } catch (e) {
533â†’        // PTY may have already exited, ignore resize errors
534â†’        console.log('PTY resize ignored (may have exited):', id)
535â†’      }
536â†’    }, debounceMs)
537â†’  }
538â†’
539â†’  private cleanupProcess(id: string): void {
540â†’    const proc = this.processes.get(id)
541â†’    if (proc) {
542â†’      // Clear pending resize debounce
543â†’      if (proc.resizeTimeout) {
544â†’        clearTimeout(proc.resizeTimeout)
545â†’        proc.resizeTimeout = undefined
546â†’      }
547â†’      // Dispose all event listeners first
548â†’      for (const disposable of proc.disposables) {
549â†’        try {
550â†’          disposable.dispose()
551â†’        } catch (e) {
552â†’          // Ignore dispose errors
553â†’        }
554â†’      }
555â†’      proc.disposables.length = 0
556â†’    }
557â†’    this.processes.delete(id)
558â†’    this.dataCallbacks.delete(id)
559â†’    this.exitCallbacks.delete(id)
560â†’  }
561â†’
562â†’  kill(id: string): void {
563â†’    const proc = this.processes.get(id)
564â†’    if (proc) {
565â†’      try {
566â†’        // Windows doesn't support SIGKILL, use default signal
567â†’        if (isWindows) {
568â†’          proc.pty.kill()
569â†’        } else {
570â†’          proc.pty.kill('SIGKILL')
571â†’        }
572â†’      } catch (e) {
573â†’        // Process may already be dead
574â†’      }
575â†’      this.cleanupProcess(id)
576â†’    }
577â†’  }
578â†’
579â†’  killAll(): void {
580â†’    console.log(`Killing ${this.processes.size} PTY processes`)
581â†’    for (const [id] of this.processes) {
582â†’      this.kill(id)
583â†’    }
584â†’    this.processes.clear()
585â†’  }
586â†’
587â†’  getProcess(id: string): ClaudeProcess | undefined {
588â†’    return this.processes.get(id)
589â†’  }
590â†’
591â†’  onData(id: string, callback: (data: string) => void): void {
592â†’    this.dataCallbacks.set(id, callback)
593â†’  }
594â†’
595â†’  onExit(id: string, callback: (code: number) => void): void {
596â†’    this.exitCallbacks.set(id, callback)
597â†’  }
