599â†’  // Orchestrator API: list all active sessions
600â†’  listSessions(): Array<{ id: string; cwd: string; backend: string; sessionId?: string; spawnedAt: number }> {
601â†’    const sessions: Array<{ id: string; cwd: string; backend: string; sessionId?: string; spawnedAt: number }> = []
602â†’    for (const [id, proc] of this.processes) {
603â†’      sessions.push({
604â†’        id,
